features.snippet:
output reg o_b;
always @(posedge i_clk) if ((i_val)&&(!o_a)) o_b <= 1'b0;
always @(posedge i_clk) if ((i_val)&&(o_a)) o_b <= 1'b1;

output reg o_a, o_b;
always @(posedge i_clk) o_a <= i_val;
always @(posedge i_clk) if (o_a) o_b <= 1'b1;
always @(posedge i_clk) if (!o_a) o_b <= 1'b0;
